// EmailSenderService.java — Replace synchronous call with async pattern
private final ExecutorService httpExecutor = Executors.newFixedThreadPool(16);

public void sendWithRetry(OrderConfirmedEvent event) {
    // Send email (existing logic)
    emailProvider.send(event.getRecipient(), event.getEmailBody());

    // Fire-and-forget async HTTP callback to delivery-tracker-api
    CompletableFuture.runAsync(() -> {
        try {
            deliveryTrackerClient.confirmDelivery(event.getOrderId());
        } catch (Exception e) {
            log.warn("Async delivery confirmation failed for order={}, will retry via DLQ", event.getOrderId(), e);
            dlqProducer.send(event); // Send to dead-letter queue for retry
        }
    }, httpExecutor);
    // Consumer thread returns immediately — Kafka offset can be committed
}

// Also add circuit breaker to DeliveryTrackerClient:
@CircuitBreaker(name = "deliveryTracker", fallbackMethod = "confirmDeliveryFallback")
public void confirmDelivery(String orderId) {
    restTemplate.postForEntity(trackerUrl + "/confirm/" + orderId, null, Void.class);
}

public void confirmDeliveryFallback(String orderId, Throwable t) {
    log.warn("Circuit open for delivery-tracker-api, order={}", orderId);
    dlqProducer.send(orderId);
}

